sql:
SELECT liquid_name
FROM pure_liquids
WHERE boiling_point > 100.0;

external_knowledge:
- 'substances' refers to pure liquids;
- 'enthalpy change required for vaporization' refers to the enthalpy of vaporization;
- 'typical values' implies the average value calculated from the experimental data.

sql:
SELECT AVG(boiling_point) AS avg_boiling_point
FROM pure_liquids
WHERE state_of_matter = 'liquid';

SELECT AVG(enthalpy_vaporization) AS average_enthalpy_vaporization
FROM thermodynamic_properties
WHERE temperature = 25;

SELECT AVG(enthalpy_vaporization) AS average_enthalpy_vaporization
FROM thermodynamic_properties
WHERE temperature = 25.0;

SELECT AVG(enthalpy_vaporization) AS average_enthalpy_vaporization
FROM thermodynamic_properties
WHERE temperature = 30.0 AND pressure = 1.0;

SELECT COUNT(DISTINCT user_id) AS unique_users_accessed
FROM access_logs
WHERE liquid_id = 1 AND temperature = 25.0 AND pressure = 1.0;

SELECT AVG(molecular_weight) AS average_molecular_weight
FROM pure_liquids
WHERE state_of_matter = 'liquid' AND boiling_point > -50;

SELECT liquid_name
FROM pure_liquids
WHERE boiling_point = (SELECT MAX(boiling_point) FROM pure_liquids);

SELECT AVG(boiling_point) AS average_boiling_point
FROM pure_liquids
WHERE state_of_matter = 'gas';

SELECT AVG(specific_heat) AS average_specific_heat
FROM thermodynamic_properties
WHERE temperature = 25.0 AND pressure = 1.0 AND source = 'theoretical';
